import json
p='.archon/logs/iter-010/gf-torsion-iter009/blueprint-reviewer-dag010.jsonl'
texts=[]
with open(p) as f:
    for line in f:
        try: o=json.loads(line)
        except: continue
        # find any string field that looks like report
        def walk(x):
            if isinstance(x,str): 
                if len(x)>200: texts.append(x)
            elif isinstance(x,dict):
                for v in x.values(): walk(v)
            elif isinstance(x,list):
                for v in x: walk(v)
        walk(o)
print('num long strings:',len(texts))
if texts:
    print('=== LAST LONG STRING ===')
    print(texts[-1][:5000])
"

