import json
p='.archon/proof-journal/current_session/attempts_raw.jsonl'
import os
if os.path.exists(p):
    files={}
    n=0
    with open(p) as f:
        for line in f:
            n+=1
            try:o=json.loads(line)
            except:continue
            fp=o.get('file') or o.get('file_path') or ''
            files[fp]=files.get(fp,0)+1
    print('total lines',n)
    for k,v in files.items(): print(v,k)
else: print('no current_session attempts_raw')
"

